<template>
  <div style="font-family: -apple-system, BlinkMacSystemFont, 'PingFang SC', 'Microsoft YaHei', sans-serif">
    <!-- 说明 -->
    <div
      style="
        margin-bottom: 14px;
        padding: 12px 14px;
        background: rgba(124, 58, 237, 0.12);
        border: 0.5px solid rgba(124, 58, 237, 0.3);
        border-radius: 12px;
      "
    >
      <p style="margin: 0 0 4px 0; color: #c4b5fd; font-size: 13px">
        <i class="fa-solid fa-robot" style="margin-right: 6px"></i>对话式写卡助手
      </p>
      <p style="margin: 0; color: #9ca3af; font-size: 11px; line-height: 1.6">
        用一句话描述你想要的角色，助手会追问关键设定 → 给出人物大纲 → 生成完整角色卡 → 配套开场白与世界书。每一步都能确认或重做。
      </p>
    </div>

    <!-- 模式切换 -->
    <div style="display: flex; gap: 8px; margin-bottom: 12px; flex-wrap: wrap">
      <button :style="modeBtnStyle('create')" @click="switchMode('create')">
        <i class="fa-solid fa-wand-magic-sparkles"></i> 新建创作
      </button>
      <button :style="modeBtnStyle('worldbook')" @click="switchMode('worldbook')">
        <i class="fa-solid fa-book-sparkles"></i> 世界书卡(进阶)
      </button>
      <button :style="modeBtnStyle('rewrite')" @click="switchMode('rewrite')">
        <i class="fa-solid fa-pen-to-square"></i> 改写当前角色卡
      </button>
    </div>

    <!-- 阶段进度（仅新建模式显示） -->
    <div v-if="mode === 'create'" style="display: flex; gap: 6px; margin-bottom: 12px; flex-wrap: wrap">
      <span v-for="step in stageSteps" :key="step.key" :style="stagePillStyle(step.key)">
        {{ step.label }}
      </span>
    </div>

    <!-- 世界书卡模式说明 -->
    <div
      v-if="mode === 'worldbook'"
      style="margin-bottom: 12px; padding: 8px 12px; background: rgba(124,58,237,0.12); border: 0.5px solid rgba(124,58,237,0.3); border-radius: 10px; color: #c4b5fd; font-size: 11px; line-height: 1.6"
    >
      <i class="fa-solid fa-book-sparkles" style="margin-right: 4px"></i>
      世界书优先模式：设定全部拆进世界书条目（蓝灯常驻=硬性约束/人设/关系，绿灯触发=配角/世界观/NSFW），角色描述位只留一句提示，最省 token、最不容易跑偏。先说说你想要的角色，问够了会直接产出整套条目，可一键写入。
    </div>

    <!-- 参考卡（新建/世界书卡模式）：可加多张，AI 综合借鉴它们的写法做新角色 -->
    <div
      v-if="mode === 'create' || mode === 'worldbook'"
      style="
        margin-bottom: 12px;
        padding: 10px 12px;
        background: rgba(30, 41, 59, 0.4);
        border: 0.5px solid rgba(84, 107, 131, 0.3);
        border-radius: 10px;
      "
    >
      <div style="display: flex; align-items: center; gap: 8px">
        <span style="color: #9ca3af; font-size: 12px; white-space: nowrap">
          <i class="fa-solid fa-clone" style="margin-right: 4px"></i>参考卡（可多张）
        </span>
        <select v-model="referenceToAdd" :style="fieldSelectStyle" style="flex: 1" @change="addReference">
          <option value="">选择一张加入参考…</option>
          <option v-for="c in characters" :key="c.avatar" :value="c.avatar">{{ c.name }}</option>
        </select>
      </div>
      <div
        v-if="state.referenceCards && state.referenceCards.length"
        style="display: flex; flex-wrap: wrap; gap: 6px; margin-top: 8px"
      >
        <span
          v-for="(r, idx) in state.referenceCards"
          :key="idx"
          style="
            display: inline-flex;
            align-items: center;
            gap: 6px;
            padding: 4px 10px;
            background: rgba(124, 58, 237, 0.25);
            border: 0.5px solid rgba(124, 58, 237, 0.5);
            border-radius: 999px;
            color: #c4b5fd;
            font-size: 12px;
          "
        >
          {{ r.name }}
          <i
            class="fa-solid fa-xmark"
            style="cursor: pointer; opacity: 0.8"
            title="移除"
            @click="removeReference(idx)"
          ></i>
        </span>
      </div>
    </div>

    <!-- 对话区 -->
    <div
      ref="chatBox"
      style="
        max-height: 380px;
        overflow-y: auto;
        padding: 4px;
        margin-bottom: 12px;
        display: flex;
        flex-direction: column;
        gap: 10px;
      "
    >
      <div v-if="state.messages.length === 0" style="color: #6b7280; font-size: 13px; text-align: center; padding: 24px 0">
        <template v-if="mode === 'rewrite'">改写当前角色卡，例如：「让她更毒舌一点，再补一段和用户的过往」</template>
        <template v-else-if="mode === 'worldbook'">说说你想要的角色（可多张参考），助手问够关键设定后会直接产出整套世界书条目，一键写入。</template>
        <template v-else>例如：「帮我做一个高冷但护短的剑修师姐，和用户是师姐弟关系」。不知道怎么描述？上面选一张喜欢的「参考卡」，AI 会照着它的写法做新角色。</template>
      </div>

      <div v-for="(msg, i) in state.messages" :key="i" :style="bubbleWrapStyle(msg.role)">
        <div :style="bubbleStyle(msg.role)">
          <div style="white-space: pre-wrap; word-break: break-word">{{ msg.content }}</div>

          <!-- 产物操作按钮 -->
          <div v-if="msg.artifact" style="margin-top: 10px; display: flex; gap: 8px; flex-wrap: wrap">
            <button v-if="msg.artifact.type === 'outline'" :style="miniBtn('#7c3aed')" :disabled="busy" @click="confirmOutline">
              <i class="fa-solid fa-check"></i> 按这个生成角色卡
            </button>
            <button v-if="msg.artifact.type === 'outline'" :style="miniBtn('#3a3a3a', '#ddd')" :disabled="busy" @click="redoOutline">
              <i class="fa-solid fa-rotate"></i> 重做大纲
            </button>

            <button v-if="msg.artifact.type === 'card'" :style="miniBtn('#0a84ff')" @click="copyText(msg.artifact.text)">
              <i class="fa-solid fa-copy"></i> 复制角色卡
            </button>
            <select v-model="insertField" :style="fieldSelectStyle">
              <option v-for="o in insertFieldOptions" :key="o.value" :value="o.value">插入到：{{ o.label }}</option>
            </select>
            <button v-if="msg.artifact.type === 'card'" :style="miniBtn('#ff9f0a')" :disabled="busy" @click="insertCard(msg.artifact.text)">
              <i class="fa-solid fa-file-import"></i> 插入到当前角色
            </button>
            <button v-if="msg.artifact.type === 'card'" :style="miniBtn('#30d158')" :disabled="busy" @click="genExtras">
              <i class="fa-solid fa-wand-magic-sparkles"></i> 生成开场白+世界书
            </button>
            <button v-if="msg.artifact.type === 'card'" :style="miniBtn('#3a3a3a', '#ddd')" :disabled="busy" @click="redoCard">
              <i class="fa-solid fa-rotate"></i> 重做角色卡
            </button>
            <!-- 局部微调：只在最后一条卡片消息上显示 -->
            <div
              v-if="msg.artifact.type === 'card' && i === lastCardIndex"
              style="width: 100%; display: flex; gap: 6px; margin-top: 4px"
            >
              <input
                v-model="tweakInput"
                :disabled="busy"
                placeholder="想微调哪里？如：让性格更毒舌、丰富外貌…"
                style="flex: 1; padding: 7px 10px; background: rgba(30,41,59,0.6); border: 0.5px solid rgba(84,107,131,0.4); border-radius: 8px; color: #e8e8e8; font-size: 12px"
                @keydown.enter.prevent="tweakCard"
              />
              <button :style="miniBtn('#7c3aed')" :disabled="busy || !tweakInput.trim()" @click="tweakCard">
                <i class="fa-solid fa-sliders"></i> 微调
              </button>
            </div>

            <button
              v-if="msg.artifact.type === 'extras' && msg.artifact.data?.greeting"
              :style="miniBtn('#0a84ff')"
              @click="copyText(msg.artifact.data.greeting)"
            >
              <i class="fa-solid fa-copy"></i> 复制开场白
            </button>
            <button
              v-if="msg.artifact.type === 'extras' && msg.artifact.data?.worldbook?.length"
              :style="miniBtn('#667eea')"
              :disabled="busy"
              @click="writeWorldbook(msg.artifact.data.worldbook)"
            >
              <i class="fa-solid fa-book-medical"></i> 写入 {{ msg.artifact.data.worldbook.length }} 条世界书
            </button>

            <button
              v-if="msg.artifact.type === 'worldbook' && msg.artifact.data"
              :style="miniBtn('#7c3aed')"
              :disabled="busy"
              @click="applyCard(msg.artifact.data)"
            >
              <i class="fa-solid fa-file-export"></i> 写入世界书卡（条目+描述+开场白）
            </button>
            <button
              v-if="msg.artifact.type === 'worldbook' && msg.artifact.data"
              :style="miniBtn('#0a84ff')"
              @click="exportCardJson(msg.artifact.data)"
            >
              <i class="fa-solid fa-download"></i> 导出 JSON
            </button>
          </div>
        </div>
      </div>

      <div v-if="busy" :style="bubbleWrapStyle('assistant')">
        <div :style="bubbleStyle('assistant')">
          <i class="fa-solid fa-spinner fa-spin"></i> {{ busyText }}
        </div>
      </div>
    </div>

    <!-- 输入区 -->
    <div style="display: flex; gap: 8px; align-items: flex-end">
      <textarea
        v-model="input"
        :disabled="busy || state.stage === 'done'"
        rows="2"
        :placeholder="mode === 'rewrite' ? '描述你想怎么改写当前角色卡…' : '描述你想要的角色，或回答助手的追问…'"
        style="
          flex: 1;
          resize: vertical;
          padding: 10px 12px;
          background: rgba(30, 41, 59, 0.5);
          border: 0.5px solid rgba(84, 107, 131, 0.4);
          border-radius: 10px;
          color: #e8e8e8;
          font-size: 13px;
          font-family: inherit;
        "
        @keydown.enter.exact.prevent="send"
      ></textarea>
      <button :style="sendBtn" :disabled="busy || !input.trim()" @click="send">
        <i class="fa-solid fa-paper-plane"></i>
      </button>
    </div>

    <div style="margin-top: 10px; display: flex; gap: 8px">
      <button :style="miniBtn('#3a3a3a', '#ddd')" :disabled="busy" @click="resetAgent">
        <i class="fa-solid fa-broom"></i> 新建会话
      </button>
      <button v-if="canUndoInsert" :style="miniBtn('#ff453a')" :disabled="busy" @click="undoInsert">
        <i class="fa-solid fa-rotate-left"></i> 撤销插入
      </button>
    </div>
  </div>
</template>

<script setup lang="ts">
import { computed, nextTick, onMounted, reactive, ref } from 'vue';
import { storeToRefs } from 'pinia';
import { useSettingsStore } from '../../settings';
import { copyToClipboard } from '../../utils';
import { translateError } from '../../utils/error-handler';
import { useWorldbook } from './useToolsCommon';
import {
  agentCardStream,
  agentClarify,
  agentExtras,
  agentOutline,
  agentRewriteCard,
  agentStructuredCard,
  agentTweakCard,
  applyWorldbookCard,
  buildWorldbookCardJson,
  clearAgentDraft,
  createAgentState,
  insertCardToCharacter,
  listAllCharacters,
  loadAgentDraft,
  readCharacterCardByAvatar,
  readCurrentCharacterCard,
  restoreCharacterField,
  saveAgentDraft,
  type AgentMessage,
  type AgentStage,
  type AgentState,
  type CharacterListItem,
  type CharField,
  type WorldbookCard,
} from '../../utils/card-agent';

const settingsStore = useSettingsStore();
const { settings } = storeToRefs(settingsStore);
const { availableWorldbooks, loadAvailableWorldbooks } = useWorldbook();

const state = reactive<AgentState>(createAgentState());
const input = ref('');
const busy = ref(false);
const busyText = ref('助手思考中…');
const chatBox = ref<HTMLElement | null>(null);
const mode = ref<'create' | 'rewrite' | 'worldbook'>('create');
const insertField = ref<'description' | 'personality' | 'scenario' | 'first_mes' | 'mes_example'>('description');
const characters = ref<CharacterListItem[]>([]);
const referenceToAdd = ref('');
const insertFieldOptions = [
  { value: 'description', label: '角色描述' },
  { value: 'personality', label: '性格' },
  { value: 'scenario', label: '场景' },
  { value: 'first_mes', label: '开场白' },
  { value: 'mes_example', label: '对话示例' },
] as const;

const stageSteps: { key: AgentStage; label: string }[] = [
  { key: 'clarify', label: '① 澄清需求' },
  { key: 'outline', label: '② 人物大纲' },
  { key: 'card', label: '③ 完整角色卡' },
  { key: 'extras', label: '④ 配套产物' },
];

const scrollToBottom = () => {
  nextTick(() => {
    if (chatBox.value) chatBox.value.scrollTop = chatBox.value.scrollHeight;
  });
};

// 最后一条「角色卡」消息的下标（只在它上面显示微调输入框）
const lastCardIndex = computed(() => {
  for (let i = state.messages.length - 1; i >= 0; i--) {
    if (state.messages[i].artifact?.type === 'card') return i;
  }
  return -1;
});

const pushMsg = (msg: AgentMessage) => {
  state.messages.push(msg);
  scrollToBottom();
  persist();
};

const persist = () => {
  // 只在有实质内容时保存，避免空会话也写存储
  if (state.messages.length > 0) saveAgentDraft(state, mode.value);
};

// 进入工具时恢复上次未完成的会话草稿
onMounted(() => {
  try {
    characters.value = listAllCharacters();
  } catch {
    /* ignore */
  }
  try {
    const draft = loadAgentDraft();
    if (draft && draft.state.messages.length > 0) {
      Object.assign(state, draft.state);
      mode.value = draft.mode === 'rewrite' ? 'rewrite' : 'create';
      scrollToBottom();
    }
  } catch {
    /* ignore */
  }
});

// 添加一张参考卡
const addReference = () => {
  const avatar = referenceToAdd.value;
  if (!avatar) return;
  const item = characters.value.find(c => c.avatar === avatar);
  if (!state.referenceCards) state.referenceCards = [];
  if (state.referenceCards.some(r => r.name === item?.name)) {
    window.toastr.info('这张卡已经在参考列表里了');
    referenceToAdd.value = '';
    return;
  }
  const text = readCharacterCardByAvatar(avatar);
  if (text) {
    state.referenceCards.push({ name: item?.name || '未命名', text });
    window.toastr.info(`已加入参考：${item?.name || ''}`);
    persist();
  } else {
    window.toastr.warning('这张卡没读到内容，换一张试试');
  }
  referenceToAdd.value = '';
};

// 移除一张参考卡
const removeReference = (idx: number) => {
  if (!state.referenceCards) return;
  state.referenceCards.splice(idx, 1);
  persist();
};

const aiSettings = () => settings.value as any;

const send = async () => {
  const text = input.value.trim();
  if (!text || busy.value) return;
  input.value = '';
  pushMsg({ role: 'user', content: text });

  busy.value = true;
  busyText.value = '助手思考中…';
  try {
    // 改写模式：直接基于当前角色卡 + 用户需求改写，跳过澄清/大纲
    if (mode.value === 'rewrite') {
      const existing = readCurrentCharacterCard();
      if (!existing) {
        pushMsg({ role: 'assistant', content: '没读到当前角色卡。请确认已打开一个角色再试，或切换到「新建创作」模式从零创作。' });
        return;
      }
      busyText.value = '正在改写当前角色卡…';
      const card = await agentRewriteCard(existing, text, aiSettings());
      state.card = card;
      state.stage = 'card';
      pushMsg({
        role: 'assistant',
        content: '按你的需求改写好了：\n\n' + card,
        artifact: { type: 'card', text: card },
      });
      return;
    }

    // 新建模式：澄清阶段
    const result = await agentClarify(state, text, aiSettings());
    for (const f of result.facts) {
      if (f && !state.facts.includes(f)) state.facts.push(f);
    }
    pushMsg({ role: 'assistant', content: result.reply });

    if (result.ready) {
      if (mode.value === 'worldbook') {
        await runStructuredCard();
      } else {
        state.stage = 'outline';
        await runOutline();
      }
    }
  } catch (e) {
    pushMsg({ role: 'assistant', content: '出错了：' + translateError(e, '思考') });
  } finally {
    busy.value = false;
  }
};

const runOutline = async () => {
  busy.value = true;
  busyText.value = '正在梳理人物大纲…';
  try {
    const outline = await agentOutline(state, aiSettings());
    state.outline = outline;
    pushMsg({
      role: 'assistant',
      content: '这是我梳理的人物大纲，看看方向对不对：\n\n' + outline,
      artifact: { type: 'outline', text: outline },
    });
  } catch (e) {
    pushMsg({ role: 'assistant', content: '生成大纲出错：' + translateError(e, '生成大纲') });
  } finally {
    busy.value = false;
  }
};

const redoOutline = async () => {
  if (busy.value) return;
  await runOutline();
};

// 世界书卡模式：产出结构化条目集
const lastWorldbookCard = ref<WorldbookCard | null>(null);
const runStructuredCard = async () => {
  busy.value = true;
  busyText.value = '正在按「世界书优先」规范生成结构化卡…';
  const idx = state.messages.length;
  state.messages.push({ role: 'assistant', content: '世界书卡生成中…\n\n', artifact: { type: 'worldbook', text: '' } });
  scrollToBottom();
  try {
    const card = await agentStructuredCard(state, aiSettings(), full => {
      const m = state.messages[idx];
      if (m) {
        m.content = '世界书卡生成中…\n\n' + full;
        scrollToBottom();
      }
    });
    lastWorldbookCard.value = card;
    state.stage = 'done';
    const blue = card.entries.filter(e => e.constant);
    const green = card.entries.filter(e => !e.constant);
    let summary = `已生成「世界书卡」：${card.charName}\n\n`;
    summary += `📌 蓝灯常驻 ${blue.length} 条：\n${blue.map(e => '· ' + e.title).join('\n')}\n\n`;
    summary += `🔑 绿灯触发 ${green.length} 条：\n${green.map(e => `· ${e.title}（${e.keys.join('/')}）`).join('\n')}\n\n`;
    summary += `📝 开场白 ${card.greetings.length} 篇；角色描述位将只放一句提示。`;
    const m = state.messages[idx];
    if (m) {
      m.content = summary;
      if (m.artifact) m.artifact.data = card;
    }
    persist();
  } catch (e) {
    const m = state.messages[idx];
    if (m) m.content = '生成世界书卡出错：' + translateError(e, '生成世界书卡');
    persist();
  } finally {
    busy.value = false;
  }
};

const applyCard = async (card: WorldbookCard) => {
  if (busy.value) return;
  busy.value = true;
  busyText.value = '正在写入世界书…';
  try {
    const wb = await applyWorldbookCard(card);
    window.toastr.success(`已写入世界书「${wb}」：${card.entries.length} 条 + 描述位 + 开场白`);
  } catch (e) {
    window.toastr.error(translateError(e, '写入世界书卡'));
  } finally {
    busy.value = false;
  }
};

/** 把世界书卡导出为 SillyTavern V2 角色卡 JSON 文件并触发下载 */
const exportCardJson = (card: WorldbookCard) => {
  try {
    const json = buildWorldbookCardJson(card);
    const text = JSON.stringify(json, null, 2);
    const safeName = (card.charName || '新角色').replace(/[<>:"/\\|?*]/g, '_').trim();
    const blob = new Blob([text], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${safeName}_全封装版.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    setTimeout(() => URL.revokeObjectURL(url), 1000);
    window.toastr.success(`已导出「${safeName}_全封装版.json」，可直接导入酒馆`);
  } catch (e) {
    window.toastr.error(translateError(e, '导出 JSON'));
  }
};

const confirmOutline = async () => {
  if (busy.value) return;
  state.stage = 'card';
  busy.value = true;
  busyText.value = '正在生成完整角色卡…';
  // 先放一个空的卡片气泡，流式往里填
  const idx = state.messages.length;
  state.messages.push({ role: 'assistant', content: '完整角色卡生成中…\n\n', artifact: { type: 'card', text: '' } });
  scrollToBottom();
  try {
    const card = await agentCardStream(state, aiSettings(), full => {
      const m = state.messages[idx];
      if (m) {
        m.content = '完整角色卡来啦：\n\n' + full;
        if (m.artifact) m.artifact.text = full;
        scrollToBottom();
      }
    });
    state.card = card;
    const m = state.messages[idx];
    if (m) {
      m.content = '完整角色卡来啦：\n\n' + card;
      if (m.artifact) m.artifact.text = card;
    }
    persist();
  } catch (e) {
    const m = state.messages[idx];
    if (m) m.content = '生成角色卡出错：' + translateError(e, '生成角色卡');
    persist();
  } finally {
    busy.value = false;
  }
};

const redoCard = async () => {
  if (busy.value) return;
  await confirmOutline();
};

const genExtras = async () => {
  if (busy.value) return;
  state.stage = 'extras';
  busy.value = true;
  busyText.value = '正在生成开场白与世界书…';
  try {
    const extras = await agentExtras(state, aiSettings());
    let text = '';
    if (extras.greeting) text += '【开场白】\n' + extras.greeting + '\n\n';
    if (extras.worldbook.length) {
      text += '【世界书候选】\n' + extras.worldbook.map((w, i) => `${i + 1}. ${w.title}：${w.content}`).join('\n');
    }
    state.stage = 'done';
    pushMsg({
      role: 'assistant',
      content: text || '已生成配套产物。',
      artifact: { type: 'extras', text, data: extras },
    });
  } catch (e) {
    pushMsg({ role: 'assistant', content: '生成配套产物出错：' + translateError(e, '生成配套产物') });
  } finally {
    busy.value = false;
  }
};

const copyText = async (text: string) => {
  await copyToClipboard(text, '已复制到剪贴板');
};

const lastInsertBackup = ref<{ field: CharField; backup: string } | null>(null);
const canUndoInsert = ref(false);

const insertCard = async (card: string) => {
  if (busy.value) return;
  busy.value = true;
  busyText.value = '正在插入到当前角色…';
  try {
    const result = await insertCardToCharacter(card, insertField.value);
    const label = insertFieldOptions.find(o => o.value === insertField.value)?.label || insertField.value;
    if (result.ok) {
      lastInsertBackup.value = { field: result.field, backup: result.backup };
      canUndoInsert.value = true;
      window.toastr.success(`已插入到「${label}」，写错了可点下方「撤销插入」恢复`);
    } else {
      window.toastr.error('插入失败：未找到当前角色或接口不可用');
    }
  } catch (e) {
    window.toastr.error(translateError(e, '插入角色'));
  } finally {
    busy.value = false;
  }
};

const undoInsert = async () => {
  if (busy.value || !lastInsertBackup.value) return;
  busy.value = true;
  busyText.value = '正在撤销插入…';
  try {
    const { field, backup } = lastInsertBackup.value;
    const ok = await restoreCharacterField(field, backup);
    const label = insertFieldOptions.find(o => o.value === field)?.label || field;
    if (ok) {
      canUndoInsert.value = false;
      lastInsertBackup.value = null;
      window.toastr.success(`已撤销，「${label}」恢复成插入前的内容`);
    } else {
      window.toastr.error('撤销失败');
    }
  } catch (e) {
    window.toastr.error(translateError(e, '撤销'));
  } finally {
    busy.value = false;
  }
};

const tweakInput = ref('');
const tweakCard = async () => {
  const req = tweakInput.value.trim();
  if (!req || busy.value || !state.card) return;
  tweakInput.value = '';
  pushMsg({ role: 'user', content: '微调：' + req });
  busy.value = true;
  busyText.value = '正在微调角色卡…';
  const idx = state.messages.length;
  state.messages.push({ role: 'assistant', content: '微调中…\n\n', artifact: { type: 'card', text: '' } });
  scrollToBottom();
  try {
    const card = await agentTweakCard(state.card, req, aiSettings(), full => {
      const m = state.messages[idx];
      if (m) {
        m.content = '微调后的角色卡：\n\n' + full;
        if (m.artifact) m.artifact.text = full;
        scrollToBottom();
      }
    });
    state.card = card;
    const m = state.messages[idx];
    if (m) {
      m.content = '微调后的角色卡：\n\n' + card;
      if (m.artifact) m.artifact.text = card;
    }
    persist();
  } catch (e) {
    const m = state.messages[idx];
    if (m) m.content = '微调出错：' + translateError(e, '微调');
    persist();
  } finally {
    busy.value = false;
  }
};

const writeWorldbook = async (entries: { title: string; content: string; keys: string[] }[]) => {
  if (busy.value) return;
  try {
    const TH = (window as any).TavernHelper;
    if (typeof TH?.createWorldbookEntries !== 'function') {
      window.toastr.error('世界书功能需要酒馆助手支持');
      return;
    }
    await loadAvailableWorldbooks();
    const names: string[] = availableWorldbooks.value || [];
    if (names.length === 0) {
      window.toastr.warning('没有可用的世界书，请先在酒馆里创建或绑定一本');
      return;
    }
    // 优先写入当前聊天绑定的世界书，否则第一本
    let target = '';
    try {
      target = TH.getChatWorldbookName?.('current') || '';
    } catch {
      /* ignore */
    }
    if (!target) target = names[0];

    const payload = entries.map((w, i) => ({
      name: w.title || `角色设定_${i + 1}`,
      enabled: true,
      strategy: {
        type: 'selective' as const,
        keys: w.keys?.length ? w.keys : [w.title],
        keys_secondary: { logic: 'and_any' as const, keys: [] },
        scan_depth: 'same_as_global' as const,
      },
      position: { type: 'before_character_definition' as const, role: 'system' as const, depth: 1 },
      content: w.content,
      comment: '写卡助手生成 - ' + new Date().toLocaleString(),
      insertion_order: i,
      recursion: { prevent_incoming: true, prevent_outgoing: true, delay_until: null },
      uid: Date.now() + i,
    }));
    await TH.createWorldbookEntries(target, payload, { render: 'immediate' });
    window.toastr.success(`已写入 ${payload.length} 条世界书到「${target}」`);
  } catch (e) {
    window.toastr.error(translateError(e, '写入世界书'));
  }
};

const resetAgent = () => {
  if (busy.value) return;
  state.stage = 'clarify';
  state.messages = [];
  state.facts = [];
  state.outline = undefined;
  state.card = undefined;
  state.referenceCards = undefined;
  input.value = '';
  referenceToAdd.value = '';
  clearAgentDraft();
};

const switchMode = (m: 'create' | 'rewrite' | 'worldbook') => {
  if (busy.value || mode.value === m) return;
  mode.value = m;
  resetAgent();
};

const modeBtnStyle = (m: 'create' | 'rewrite' | 'worldbook') => ({
  flex: '1',
  padding: '8px 10px',
  borderRadius: '10px',
  fontSize: '13px',
  fontWeight: 600,
  cursor: 'pointer',
  border: mode.value === m ? '0.5px solid rgba(124,58,237,0.6)' : '0.5px solid rgba(84,107,131,0.3)',
  background: mode.value === m ? 'rgba(124,58,237,0.25)' : 'rgba(30,41,59,0.5)',
  color: mode.value === m ? '#c4b5fd' : '#9ca3af',
});

const fieldSelectStyle = {
  padding: '6px 8px',
  background: 'rgba(30,41,59,0.6)',
  border: '0.5px solid rgba(84,107,131,0.4)',
  borderRadius: '8px',
  color: '#e8e8e8',
  fontSize: '12px',
};

// ===== 样式 =====
const stagePillStyle = (key: AgentStage) => {
  const order: AgentStage[] = ['clarify', 'outline', 'card', 'extras', 'done'];
  const active = order.indexOf(state.stage) >= order.indexOf(key);
  return {
    padding: '4px 10px',
    borderRadius: '999px',
    fontSize: '11px',
    fontWeight: 600,
    background: active ? 'rgba(124,58,237,0.25)' : 'rgba(60,60,66,0.4)',
    color: active ? '#c4b5fd' : '#8a8a8e',
    border: active ? '0.5px solid rgba(124,58,237,0.5)' : '0.5px solid transparent',
  };
};

const bubbleWrapStyle = (role: string) => ({
  display: 'flex',
  justifyContent: role === 'user' ? 'flex-end' : 'flex-start',
});

const bubbleStyle = (role: string) => ({
  maxWidth: '85%',
  padding: '10px 13px',
  borderRadius: '14px',
  fontSize: '13px',
  lineHeight: '1.6',
  background: role === 'user' ? 'rgba(10,132,255,0.85)' : 'rgba(44,44,46,0.9)',
  color: role === 'user' ? '#fff' : '#e8e8e8',
  border: role === 'user' ? 'none' : '0.5px solid rgba(255,255,255,0.08)',
});

const miniBtn = (bg: string, color = '#fff') => ({
  padding: '6px 12px',
  background: bg,
  border: 'none',
  borderRadius: '8px',
  color,
  cursor: 'pointer',
  fontSize: '12px',
  fontWeight: 600,
});

const sendBtn = {
  padding: '10px 16px',
  background: '#7c3aed',
  border: 'none',
  borderRadius: '10px',
  color: '#fff',
  cursor: 'pointer',
  fontSize: '14px',
  height: 'fit-content',
};
</script>
